mapper.select:
SELECT faq_id , category , title , contents , writed_at FROM faq WHERE deleted_at IS NULL
AND category = #{category}
ORDER BY writed_at DESC
LIMIT #{firstRecordIndex}, #{recordCountPerPage}

mapper.insert:
INSERT INTO faq
( faq_id
, category
, title
, contents
, writed_user_id
, created_user_id
, updated_user_id)
VALUES ( #{faqId}
, #{category}
, #{title}
