    SELECT LAST_INSERT_ID()

mapper.update:
UPDATE faq
SET category   = #{category}
  , title      = #{title}
  , contents   = #{contents}
  , writed_at  = NOW()
  , updated_at = NOW()
  , contents   = #{contents}
WHERE faq_id = #{faqId}

UPDATE faq
SET deleted_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE faq_id = #{faqId}
